function sakurazaka(array : string[]) : string {
  let str : string = ""

  for (let i : number = array.length - 1; i >= 0; i = i - 1) {
    for (let j : number = array[i].length - 1; j >= 0; j = j - 1) {
      str = str + array[i][j]
    }
    str = str + "."
  }

  return str
}
